SELECT DISTINCT c.*
FROM conversations c
INNER JOIN conversation_members cm ON c.id = cm.conversation_id
WHERE cm.user_id = #{userId}
AND c.deleted_at IS NULL

    AND c.id > #{cursorId}

ORDER BY c.id ASC
LIMIT #{pageSize}

SELECT c.*
FROM conversations c
INNER JOIN conversation_members cm ON c.id = cm.conversation_id
WHERE cm.user_id = #{userId}
AND c.type = 'GROUP'
AND c.deleted_at IS NULL

    AND c.id > #{cursor}

ORDER BY c.id ASC
LIMIT #{limit}
